import argparse
import requests

def get_stock_price(ticker):
    # Replace with your API key
    api_key = 'YOUR_API_KEY'
    url = f'https://www.alphavantage.co/query?function=GLOBAL_QUOTE&symbol={ticker}&apikey={api_key}'
    response = requests.get(url)
    data = response.json()

    if 'Global Quote' in data:
        quote = data['Global Quote']
        price = float(quote['05. price'])
        change = float(quote['09. change'])
        return price, change
    else:
        return None, None

def main():
    parser = argparse.ArgumentParser(description='Get stock price and change')
    parser.add_argument('ticker', type=str, help='Stock ticker symbol')
    args = parser.parse_args()

    price, change = get_stock_price(args.ticker.upper())
    if price is not None:
        print(f"Current price for {args.ticker.upper()}: ${price:.2f}")
        print(f"Change: ${change:.2f}")
    else:
        print(f"Error getting stock price for {args.ticker.upper()}")

if __name__ == '__main__':
    main()

